async function synthesize(text, filename, isSSML = false, voiceName = 'zh-HK-HiuMaanNeural') {
  return new Promise((resolve, reject) => {
    const speechConfig = sdk.SpeechConfig.fromSubscription(SPEECH_KEY, SPEECH_REGION);
    speechConfig.speechSynthesisOutputFormat = sdk.SpeechSynthesisOutputFormat.Audio16Khz128KBitRateMonoMp3;

    if (!isSSML) {
      speechConfig.speechSynthesisVoiceName = voiceName;
    }

    const filePath = path.join(outDir, filename);
    const audioConfig = sdk.AudioConfig.fromAudioFileOutput(filePath);
    const synthesizer = new sdk.SpeechSynthesizer(speechConfig, audioConfig);

    const method = isSSML ? 'speakSsmlAsync' : 'speakTextAsync';

    synthesizer[method](text, (result) => {
      synthesizer.close();
      if (result.reason === sdk.ResultReason.SynthesizingAudioCompleted) {
        const stats = fs.statSync(filePath);
        console.log(`   ✅ ${filename} (${(stats.size / 1024).toFixed(1)} KB)`);
        resolve(filePath);
      } else {
        console.log(`   ❌ ${filename}: ${result.errorDetails}`);
        reject(new Error(result.errorDetails));
      }
    }, (err) => {
      synthesizer.close();
      reject(err);
    });
  });
}

async function main() {
  console.log('=== Azure Cantonese TTS v2 — All Voices × All Texts ===\n');
  console.log(`Output: ${outDir}\n`);

  let count = 0;

  for (const voice of VOICES) {
    console.log(`\n🎤 Voice: ${voice.id} (${voice.label})`);
    console.log('─'.repeat(50));

    for (const t of TEXTS) {
      const filename = `${voice.label}_${t.name}.mp3`;
      const isSSML = t.ssml !== null;
      const content = isSSML ? t.ssml(voice.id) : t.text;

      try {
        await synthesize(content, filename, isSSML, voice.id);
        count++;
      } catch (err) {
        console.log(`   ❌ ${filename}: ${err.message}`);
      }
    }
  }

  console.log(`\n=== DONE: ${count} files generated ===`);
  console.log(`\nAll files in: ${outDir}`);
  console.log('\n📋 How to evaluate:');
  console.log('   1. Compare plain vs SSML versions (e.g. 03 vs 04) — does SSML help?');
  console.log('   2. Compare voices — which sounds most natural?');
  console.log('   3. Note: the TEXT quality matters as much as the voice');
  console.log('      → If LLM generates 書面語 instead of 口語, even the best voice sounds wrong');
}

main();
